from docx import Document
from docx.shared import Pt, Inches
from docx.enum.text import WD_ALIGN_PARAGRAPH, WD_LINE_SPACING

def create_lambe_student_booklet():
    doc = Document()
    for section in doc.sections:
        section.top_margin, section.bottom_margin = Inches(1), Inches(1)
        section.left_margin, section.right_margin = Inches(1), Inches(1)

    style = doc.styles['Normal']
    style.font.name = 'Arial'
    style.font.size = Pt(14)
    style.paragraph_format.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE

    # НАСОКИ
    doc.add_heading('ДЕЛ 1: ТЕСТ-КНИШКА ЗА УЧЕНИКОТ', 1)
    doc.add_heading('НАСОКИ ЗА УЧЕНИКОТ', 2)
    doc.add_paragraph("Во овој тест ќе прочиташ еден расказ и ќе одговориш на неколку прашања за она што си го прочитал/а. Некои прашања можеби ќе ти бидат лесни, а некои потешки. За некои прашања ќе треба да го избереш најдобриот одговор со заокружување на буквата перед него (А, Б, В или Г). За други прашања ќе треба да го напишеш твојот одговор на празните линии. До прашањата каде што треба да пишуваш има назначено колку поени носи твоето објаснување. Дади сè од себе да ги одговориш сите прашања.")
    doc.add_page_break()

    # ТЕКСТ
    doc.add_heading('ДЕДО ЛАМБЕ И ГЛУВЦИТЕ', 0).alignment = WD_ALIGN_PARAGRAPH.CENTER

    paragraphs = [
        "Дедо Ламбе беше стар, сиромашен, но многу весел човек. Живееше сам во една мала, трошна куќарка на крајот од селото. Неговата куќа беше полна со пукнатини во ѕидовите и дупки во дрвениот под, што ја правеше совршено, топло место за живеење на едно огромно семејство глувци.",
        "Глувците беа буквално насекаде. Тие слободно трчаа низ кујната барајќи трошки, си играа криенка под стариот кревет и правеа голема врева секоја ноќ кога дедо Ламбе се обидуваше да спие. Тие дури и си правеа мали креветчиња од неговите стари чорапи! Дедо Ламбе ги трпеше долго време, бидејќи по природа беше добар човек, но еден ден глувците му го изедоа последното парче леб. Тогаш реши дека е доста и дека мора да преземе нешто за да ги избрка.",
        "[ 🎨 NanoBanana Prompt: A cheerful but poor old man named Grandpa Lambe sitting in a small, old, cozy wooden house. Many cute little mice are running around freely... In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Следниот ден отиде во селската продавница и купи неколку силни стапици за глувци. Внимателно ги наполни со најубавото, најмиризливото жолто сирење и ги постави во секој агол низ целата куќа.",
        "Првата ноќ, кога падна мрак и куќата стивна, глувците излегоа од своите дупки. Тие веднаш го намирисаа вкусното сирење. Но, овие глувци беа многу итри и паметни. Тие добро ги познаваа стапиците и знаеја колку се опасни. Наместо да се излажат и да го изедат сирењето, тие само се шегуваа, танцуваа околу стапиците и се смееја на планот на старецот.",
        "Следното утро, кога дедо Ламбе слезе долу, виде дека нема ниту еден фатен глушец. Стапиците стоеја недопрени. Но, наместо да се налути или разочара, тој само слатко се насмеа. Зошто Ламбе се насмеа кога виде дека нема глувци во стапиците? Тој знаеше дека тие нема да го земат сирењето првата ноќ. Тој всушност ги надитри глувците оставајќи ги да мислат дека е глупав старец. Имаше на ум еден многу подобар, генијален план за да ги измами и да се ослободи од нив.",
        "Втората ноќ, Ламбе чекаше сите глувци цврсто да заспијат во своите дупки. Потоа, зеде една голема канта со најсилното лепило на светот. Почна да работи тивко и брзо. Го намачка лепилото на ногарките од масата и со многу мака ја подигна и ја залепи масата за таванот! Потоа ги залепи столовите за таванот околу масата. Ја залепи и малата подна ламба, шарениот килим, па дури и телевизорот! Целиот мебел беше залепен наопаку, висејќи од таванот. Подот остана целосно празен и чист.",
        "[ 🎨 NanoBanana Prompt: An old man quietly and carefully gluing a wooden table, chairs, a rug, and a lamp upside down to the ceiling of his room. The floor below is completely empty... In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Околу полноќ, глувците почнаа да се будат. Тие излегоа од дупките очекувајќи повторно да се шегуваат со стапиците. Но, кога погледнаа наоколу, останаа без зборови. Тие наеднаш престанале да се смеат.",
        "„Погледнете таму горе!“ извика еден мал глушец, покажувајќи кон таванот. „Ене го подот!“\n„Па, ние како да стоиме на таванот!“ одговори друг глушец со треперлив глас, не верувајќи на своите очи.",
        "Глувците беа целосно збунети. Во нивните мали главчиња, тие мислеа дека штом мебелот е горе, тоа мора да е подот. А штом тие се долу, на празниот простор без ниту еден предмет, тие сигурно стојат на таванот и висат наопаку!",
        "„Ова е страшно! Ох, леле мајко!“ пискаа глувците во еден глас. „Почнувам да чувствувам како ми се врти во главата. Сета крв ми оди во главата.“\nПаниката почна брзо да се шири низ собата. Сега сите почнале да стануваат хистерични.",
        "„Ќе паднам во несвест ако морам да продолжам да стојам на глава!“ плачеше еден мал глушец. „Не можам да го издржам ова! Спасете не! Нека стори некој нешто, бргу!“",
        "„Мора веднаш да сториме нешто!“ извика главниот глушец. „Ако стоиме на таванот, тогаш сме свртени наопаку. За да бидеме исправени како што треба, мора веднаш да застанеме на нашите глави!“",
        "И така, сите глувци, до еден, застанаа на своите глави. Стоеја така, балансирајќи со шепите во воздухот со часови. Но, да се стои на глава е многу тешко и заморно. Бидејќи стоеја на глава премногу долго, крвта навистина им се собра во мозокот. Еден по еден, тие почнаа да паѓаат во несвест. По неколку часа, сите глувци лежеа онесвестени на празниот под.",
        "[ 🎨 NanoBanana Prompt: A group of funny little mice panicking in an empty room, standing upside down on their heads, balancing with their paws in the air. Above them, furniture is glued to the ceiling... In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]",
        "Следното утро, кога дедо Ламбе слезе долу, подот беше целосно покриен со глувци. Сите спиеја толку длабоко што не можеа ниту да се помрднат.",
        "Дедо Ламбе задоволно се насмевна. Зеде една голема плетена кошница и почна да ги собира глувците од подот. Ги стави сите внатре, цврсто ја поклопи кошницата и ги однесе далеку во шумата зад планината. Таму ги пушти на слобода, каде што ќе можат да си играат без да му пречат на никого. Потоа се врати дома, го симна мебелот од таванот и си свари топло кафе. Тој ги надитри глувците и докажа дека трпението и итрината се посилни од секој проблем!",
        "[ 🎨 NanoBanana Prompt: A happy old man sitting in a normal room, drinking a warm cup of coffee. Outside the window, a beautiful green forest can be seen. In the style of a clean children's picture book, pastel colors, white background bleed --ar 16:9 ]"
    ]

    for p in paragraphs:
        if "NanoBanana" in p:
            para = doc.add_paragraph(p)
            para.alignment = WD_ALIGN_PARAGRAPH.CENTER
            para.runs[0].italic = True
            para.runs[0].font.size = Pt(11)
        else:
            doc.add_paragraph(p).alignment = WD_ALIGN_PARAGRAPH.JUSTIFY

    # ПРАШАЊА
    doc.add_page_break()
    doc.add_heading('ПРАШАЊА ЗА ТЕКСТОТ', 1)

    mcq = {
        "1": ("Што бил најголемиот проблем на дедо Ламбе на почетокот од приказната?", ["А) Немал пари за леб.", "Б) Куќата му била полна со глувци.", "В) Куќата му била многу стара.", "Г) Му се скршил стариот мебел."]),
        "2": ("Што ставил дедо Ламбе во стапиците првата ноќ?", ["А) Лепило", "Б) Парче леб", "В) Отров", "Г) Сирење"]),
        "3": ("Што направил Ламбе втората ноќ додека глувците спиеле?", ["А) Ги избркал глувците.", "Б) Го залепил мебелот за таванот.", "В) Ги затворил сите дупки во подот.", "Г) Купил нови, посилни стапици."]),
        "5": ("Каде се наоѓал мебелот втората ноќ кога глувците излегле од дупките?", ["А) На подот", "Б) Надвор во дворот", "В) На таванот", "Г) Во шумата"]),
        "8": ("Како приказната ти покажува што глувците мислеле дека се случува?", ["А) Раскажувајќи што Ламбе мислел за глувците.", "Б) Опишувајќи каде живееле глувците.", "В) Раскажувајќи што глувците си кажувале еден на друг.", "Г) Опишувајќи какви биле глувците."]),
        "9": ("Зошто подот бил покриен со глувци кога Ламбе слегол долу последното утро?", ["А) Глувците стоеле на глава премногу долго.", "Б) Ламбе им дал на глувците премногу сирење.", "В) Глувците паднале од таванот.", "Г) Ламбе имал ставено лепило на подот."]),
        "13": ("Кои зборови најдобро ја опишуваат оваа приказна?", ["А) сериозна и тажна", "Б) страшна и возбудлива", "В) смешна и поучна", "Г) таинствена и досадна"])
    }

    open_q = {
        "4": ("Зошто Ламбе се насмеал кога видел дека нема глувци во стапиците првото утро? Објасни го твојот одговор.", 1, 2),
        "6": ("Втората ноќ, каде мислеле глувците дека стојат и што решиле да направат во врска со тоа?", 2, 3),
        "7": ("Најди и препиши една реченица од текстот која ја покажува паниката што глувците ја чувствувале втората ноќ.", 1, 2),
        "10": ("Каде ги ставил Ламбе глувците кога ги собрал од подот?", 1, 2),
        "11": ("Дали мислиш дека е лесно глувците да се излажат? Напиши една причина зошто е лесно или зошто не е лесно, користејќи докази од текстот.", 1, 3),
        "12": ("Ти дозна каков е Ламбе од она што тој го прави. Опиши каков е тој и наведи два примери што прави Ламбе, што го покажува тоа.", 3, 4),
        "14": ("Размисли што правеле Ламбе и глувците во приказната. Објасни што ја прави приказната да биде неверојатна (невозможна во вистинскиот живот).", 2, 3)
    }

    for i in range(1, 15):
        num = str(i)
        if num in mcq:
            q, opts = mcq[num]
            doc.add_paragraph(f"{num}. {q}").runs[0].bold = True
            for o in opts:
                doc.add_paragraph(f"O  {o}").paragraph_format.left_indent = Inches(0.5)
        elif num in open_q:
            q, pts, lines = open_q[num]
            p = doc.add_paragraph()
            p.add_run(f"{num}. {q}").bold = True
            p.add_run(f" [✎ {pts} поен/и]").italic = True
            for _ in range(lines):
                doc.add_paragraph("_" * 60)

    doc.add_paragraph("\n🛑 СТОП. КРАЈ НА ТЕСТОТ.")
    doc.save("PIRLS_Test_Dedo_Lambe_Ucenik.docx")

create_lambe_student_booklet()
